mapper.select:
/* DOCS_REQUEST 테이블에서 특정 상태값의 수를 가져온다. */ SELECT count(*) FROM DOCS_REQUEST request
/* 외부사용자 이면서 상태가 승인이라면 아이템 단위로 보여줘야 함. */ INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_FILE fileInfo ON requestMapping.REQUEST_NO = fileInfo.REQUEST_NO AND requestMapping.OBJECT_ID = fileInfo.OBJECT_ID INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO
WHERE 1=1
AND request.STATUS_CD = #{statusCd}
AND REQUEST_TYPE = #{requestType}
/* 외부사용자이면서 승인이면 나한테 배포된 내역을 보여줌 */ AND deployInfo.DEPLOY_USER_CD = #{sessionUser.userCd} /* 나한테 배포 */
AND request.INSERT_USER_CD = #{sessionUser.userCd} /* 내가 요청 */
AND request.BUSINESS_AREA_CD = #{sessionUser.businessAreaCd} /* 내부사용자일 경우에만 사업장코드 추가 */
AND request.OBJECT_TYPE = #{objectType}
AND request.INSERT_DT BETWEEN TO_DATE(#{startDt}, 'YYYY-MM-DD') AND TO_DATE(#{endDt}, 'YYYY-MM-DD') + INTERVAL '1 day'

/* 내가 거절한 내역 수 */
SELECT count(*)
FROM DOCS_REQUEST request
INNER JOIN DOCS_REQUEST_DETAIL detail ON detail.REQUEST_NO = request.REQUEST_NO AND detail.ACTION_CD = 'REJECT'
WHERE request.STATUS_CD = #{statusCd}
AND request.REQUEST_TYPE = #{requestType}
AND detail.ACTUAL_USER_CD = #{sessionUser.userCd}    /* 내가 거절 */

	AND request.INSERT_DT BETWEEN TO_DATE(#{startDt}, 'YYYY-MM-DD')
	AND TO_DATE(#{endDt}, 'YYYY-MM-DD') + INTERVAL '1 day'

mapper.update:
UPDATE session_config
SET session_time = #{sessionTimeout}
WHERE id = 1

mapper.select:
SELECT role_group
FROM docs_user
WHERE user_cd = #{userCd}
